class Solution:
    def baseNeg2(self, n: int) -> str:
        if n == 0:
            return '0'
        res = []
        while n != 0:
            n, remainder = divmod(n, -2)
            if remainder < 0:
                n += 1
                remainder += 2
            res.append('1' if remainder != 0 else '0')
        return ''.join(reversed(res))
